Basic Async/Await <pre><code>public async Task GetDataAsync()
{
    var data = await _httpClient.GetAsync("/api/data");
    return await data.Content.ReadAsStringAsync();
}
</code></pre>

CancellationToken <pre><code>public async Task ProcessAsync(CancellationToken cancellationToken)
{
    while (!cancellationToken.IsCancellationRequested)
    {
        // Do work
        await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);
    }
}
</code></pre>

ConfigureAwait <pre><code>// Library code: Use ConfigureAwait(false)
public async Task&lt;string&gt; GetDataAsync()
{
    var data = await _httpClient.GetAsync("/api/data")
                          .ConfigureAwait(false);
    return await data.Content.ReadAsStringAsync()
                          .ConfigureAwait(false);
}
</code></pre>

Exception Handling <pre><code>try
{
    await DoWorkAsync();
}
catch (Exception ex)
{
    // Handle exception
}
</code></pre>
